def get_weights(w, m):
    weights = []
    while m > 0:
        if m >= w:
            weights.append(w)
            m -= w
        else:
            weights.append(m)
            m = 0
        w += 1
    return weights


def main():
    w, m = map(int, input().split())
    weights = get_weights(w, m)
    if m == 0:
        print("YES")
        return
    if len(weights) == 1:
        print("NO")
        return
    left_sum = sum(weights[:len(weights) // 2])
    right_sum = sum(weights[len(weights) // 2:])
    if left_sum == right_sum:
        print("YES")
    else:
        print("NO")


if __name__ == "__main__":
    main()
